// Merges the extraction result (from Extract Invoice) with the
// validation result (from Validate Invoice) into one flat record
// ready to insert into the invoices table.
//
// Using .first() rather than .item — .item's pairedItem tracking can
// break once a node in between has completely replaced the item's shape,
// which is exactly what happens here (extraction output and validation
// output are entirely different objects).
const extraction = $('Extract Invoice').first().json;
const validation = $input.first().json;

// Capture the filename here, from the webhook node directly, rather than
// relying on binary data surviving through this Code node — Code nodes
// don't forward binary data automatically unless explicitly included in
// the returned item.
let sourceFilename = 'unknown';
try {
  const webhookItem = $('Invoice Webhook').first();
  if (webhookItem.binary && webhookItem.binary.file) {
    sourceFilename = webhookItem.binary.file.fileName || 'unknown';
  }
} catch (e) {
  // fall back to 'unknown' — not worth failing the whole record over a filename
}

return [{
  json: {
    source_filename: sourceFilename,
    vendor_name: extraction.vendor_name,
    invoice_number: extraction.invoice_number,
    issue_date: extraction.issue_date,
    total: extraction.total,
    outcome: validation.outcome,
    flags: validation.flags,
    reasons: validation.reasons,
    extracted_data: extraction,
  }
}];

