const inv = $('Merge Extraction + Validation').first().json;
const flagLines = (inv.flags || []).map(f => `• ${f}: ${inv.reasons[f] || ''}`).join('
');
const text = `🚩 Invoice needs review
Vendor: ${inv.vendor_name || 'unknown'}
Total: $${inv.total ?? 'unknown'}

${flagLines}`;
return [{ json: { text } }];
